 43→export default function SvgCanvas() {
 44→  const svgRef = useRef(null);
 45→  const isPanning = useRef(false);
 46→  const lastPanPos = useRef({ x: 0, y: 0 });
 47→  const spaceHeld = useRef(false);
 48→  const cursorPosRef = useRef({ x: 0, y: 0 });
 49→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 50→
 51→  const { dispatch, getFloor } = useProject();
 52→  const editor = useEditor();
 53→  const {
 54→    activeTool, selectedId, selectedType, toolState,
 55→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 56→    regionSelection, pastePreview,
 57→    dispatch: editorDispatch,
 58→  } = editor;
 59→
 60→  const floor = getFloor(activeFloorId);
 61→  const {
 62→    copySelection,
 63→    cutSelection,
 64→    beginPaste,
 65→    updatePastePreview,
 66→    cancelPaste,
 67→    placePaste,
 68→    previewContent,
 69→  } = usePlanClipboardController();
 70→
 71→  const tool = useEditorTool({
 72→    activeTool,
 73→    dispatch,
 74→    editorDispatch,
 75→    getFloor,
 76→    activeFloorId,
 77→    viewport,
 78→    snapEnabled,
 79→    selectedId,
 80→    selectedType,
 81→    toolState,
 82→    viewMode,
 83→  });
 84→
 85→  const getModelPos = useCallback((e) => {
 86→    const rect = svgRef.current.getBoundingClientRect();
 87→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 88→  }, [viewport]);
 89→
 90→  const handleMouseDown = useCallback((e) => {
 91→    // Middle mouse or space+left for pan
 92→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 93→      isPanning.current = true;
 94→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 95→      e.preventDefault();
 96→      return;
 97→    }
 98→
 99→    const modelPos = getModelPos(e);
100→    if (pastePreview?.active && e.button === 0) {
101→      placePaste(modelPos);
102→      return;
103→    }
104→    tool.onMouseDown(modelPos, e);
105→  }, [getModelPos, pastePreview, placePaste, tool]);
106→
107→  const handleMouseMove = useCallback((e) => {
108→    if (isPanning.current) {
109→      const dx = e.clientX - lastPanPos.current.x;
110→      const dy = e.clientY - lastPanPos.current.y;
111→      editorDispatch({ type: 'PAN', dx, dy });
112→      lastPanPos.current = { x: e.clientX, y: e.clientY };
113→      return;
114→    }
115→
116→    const modelPos = getModelPos(e);
117→    cursorPosRef.current = modelPos;
118→    setCursorPos(modelPos);
119→    if (pastePreview?.active) {
120→      updatePastePreview(modelPos);
121→      return;
122→    }
123→    tool.onMouseMove(modelPos, e);
124→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
125→
126→  const handleMouseUp = useCallback((e) => {
127→    if (isPanning.current) {
128→      isPanning.current = false;
129→      return;
130→    }
131→    if (pastePreview?.active) return;
132→    const modelPos = getModelPos(e);
133→    tool.onMouseUp(modelPos, e);
134→  }, [getModelPos, pastePreview, tool]);
135→
136→  const handleDoubleClick = useCallback((e) => {
137→    if (pastePreview?.active) return;
138→    const modelPos = getModelPos(e);
139→    tool.onDoubleClick(modelPos, e);
140→  }, [getModelPos, pastePreview, tool]);
141→
142→  const handleWheel = useCallback((e) => {
143→    e.preventDefault();
144→    const rect = svgRef.current.getBoundingClientRect();
145→    const mouseX = e.clientX - rect.left;
146→    const mouseY = e.clientY - rect.top;
147→
148→    const direction = e.deltaY < 0 ? 1 : -1;
149→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
150→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
151→
152→    // Zoom centered on cursor
153→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
154→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
155→
156→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
157→  }, [viewport, editorDispatch]);
158→
159→  useEffect(() => {
160→    if (!statusMessage) return undefined;
161→
162→    const timer = window.setTimeout(() => {
163→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
164→    }, 2500);
165→
166→    return () => window.clearTimeout(timer);
167→  }, [statusMessage, editorDispatch]);
168→
169→  useEffect(() => {
170→    const handleKeyDown = (e) => {
171→      if (isTypingTarget(e.target)) return;
172→
173→      if (e.key === ' ') {
174→        spaceHeld.current = true;
175→        e.preventDefault();
176→      }
177→
178→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
179→        const key = e.key.toLowerCase();
180→        if (key === 'c') {
181→          e.preventDefault();
182→          copySelection();
183→          return;
184→        }
185→        if (key === 'x') {
186→          e.preventDefault();
187→          cutSelection();
188→          return;
189→        }
190→        if (key === 'v') {
191→          e.preventDefault();
192→          beginPaste(cursorPosRef.current);
193→          return;
194→        }
195→      }
196→
197→      if (e.key === 'Escape' && pastePreview?.active) {
198→        e.preventDefault();
199→        cancelPaste();
200→        return;
201→      }
202→
203→      // Tool shortcuts
204→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
205→        switch (e.key.toLowerCase()) {
206→          case 'v':
207→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
208→            return;
209→          case 'm':
210→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
211→            return;
212→          case 'w':
213→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
214→            return;
215→          case 'b':
216→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
217→            return;
218→          case 't':
219→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
220→            return;
221→          case 'q':
222→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
223→            return;
224→          case 's':
225→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
226→            return;
227→          case 'r':
228→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
229→            return;
230→          case 'd':
231→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
232→            return;
233→          case 'n':
234→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
235→            return;
236→          case 'c':
237→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
238→            return;
239→        }
240→      }
241→
242→      tool.onKeyDown(e);
243→    };
244→
245→    const handleKeyUp = (e) => {
246→      if (isTypingTarget(e.target)) return;
247→
248→      if (e.key === ' ') {
249→        spaceHeld.current = false;
250→      }
251→    };
252→
253→    window.addEventListener('keydown', handleKeyDown);
254→    window.addEventListener('keyup', handleKeyUp);
255→    return () => {
256→      window.removeEventListener('keydown', handleKeyDown);
257→      window.removeEventListener('keyup', handleKeyUp);
258→    };
259→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
260→
261→  // Prevent default context menu on SVG
262→  useEffect(() => {
263→    const svg = svgRef.current;
264→    if (!svg) return;
265→    const prevent = (e) => e.preventDefault();
266→    svg.addEventListener('contextmenu', prevent);
267→    svg.addEventListener('wheel', handleWheel, { passive: false });
268→    return () => {
269→      svg.removeEventListener('contextmenu', prevent);
270→      svg.removeEventListener('wheel', handleWheel);
271→    };
272→  }, [handleWheel]);
273→
274→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
275→  const zoomPercent = Math.round(viewport.zoom * 1000);
276→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
277→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
278→    : null;
279→  const selectionCount = regionSelection?.objectCount || 0;
280→
281→  return (
282→    <div className={styles.canvasContainer}>
283→      <svg
284→        ref={svgRef}
285→        className={styles.svg}
286→        style={{ cursor }}
287→        onMouseDown={handleMouseDown}
288→        onMouseMove={handleMouseMove}
289→        onMouseUp={handleMouseUp}
290→        onDoubleClick={handleDoubleClick}
291→      >
292→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
293→          {viewMode === 'plan' && showGrid && <GridRenderer />}
294→          {viewMode === 'plan' && showGrid && (
295→            <rect
296→              x={-100000} y={-100000}
297→              width={200000} height={200000}
298→              fill="url(#grid-major)"
299→              style={{ pointerEvents: 'none' }}
300→            />
301→          )}
302→          {floor && (
303→            viewMode === 'plan' ? (
304→              <>
305→                {(floor.slabs || []).map(slab => (
306→                  <SlabRenderer key={slab.id} slab={slab} selectedId={selectedId} />
307→                ))}
308→                <RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
309→                <RoomPreview toolState={toolState} activeTool={activeTool} />
310→                <WallRenderer walls={floor.walls} columns={floor.columns || []} />
311→                <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
312→                <StairRenderer stairs={floor.stairs || []} />
313→                <ColumnRenderer columns={floor.columns || []} />
314→                <DoorRenderer doors={floor.doors} walls={floor.walls} />
315→                <WindowRenderer windows={floor.windows} walls={floor.walls} />
316→                {(floor.sectionCuts || []).map(sc => (
317→                  <SectionCutRenderer key={sc.id} sectionCut={sc} selectedId={selectedId} />
318→                ))}
319→                <AnnotationRenderer floor={floor} />
320→                <ClipboardPreviewLayer content={previewContent} />
321→                <RegionSelectionOverlay
322→                  marqueeBounds={marqueeBounds}
323→                  selectionBounds={regionSelection?.bounds || null}
324→                />
325→                <SelectionOverlay
326→                  selectedId={selectedId}
327→                  selectedType={selectedType}
328→                  floor={floor}
329→                  zoom={viewport.zoom}
330→                />
331→                <DimensionPreview toolState={toolState} activeTool={activeTool} />
332→                <WallPreview toolState={toolState} activeTool={activeTool} />
333→                <SlabPreview toolState={toolState} activeTool={activeTool} />
334→                <BeamPreview
335→                  toolState={toolState}
336→                  activeTool={activeTool}
337→                  columns={floor.columns || []}
338→                  floorLevel={floor.level}
339→                />
340→                <StairPreview
341→                  toolState={toolState}
342→                  activeTool={activeTool}
343→                  floorId={floor.id}
